trigger.body:
    rRecord RECORD;

BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

    IF INSERTING THEN
        SELECT em_sstpc_cost_process_prod, em_sstpc_project_costs INTO rRecord
        FROM M_Product_Category_Acct pca
            JOIN m_product pr ON pr.m_product_category_id = pca.m_product_category_id
        WHERE pr.m_product_id = :NEW.m_product_id;

        IF :NEW.em_sstpc_cost_process_prod IS NULL THEN
            :NEW.em_sstpc_cost_process_prod := rRecord.em_sstpc_cost_process_prod;
        END IF;

        IF :NEW.em_sstpc_project_costs IS NULL THEN
            :NEW.em_sstpc_project_costs := rRecord.em_sstpc_project_costs;
        END IF;
    END IF;

    END SSTPC_PRODUCT_ACCT_TRG
